import sys

def solve():
    input_data = sys.stdin.read().split()
    n = int(input_data[0])
    a = list(map(int, input_data[1:n+1]))

    INF = float('inf')
    MAX_XOR = 512

    # dp[v] = minimum last element of increasing subsequence with XOR = v
    dp = [INF] * MAX_XOR
    dp[0] = -1  # empty subsequence

    for x in a:
        # We need to update: for all v where dp[v] < x, consider new xor = v ^ x
        # new last element = x
        # We must be careful not to use updates from this same iteration
        new_updates = {}
        for v in range(MAX_XOR):
            if dp[v] < x:
                nv = v ^ x
                if x < dp[nv] if nv in new_updates else True:
                    if nv not in new_updates or x < new_updates[nv]:
                        new_updates[nv] = x

        for nv, val in new_updates.items():
            if val < dp[nv]:
                dp[nv] = val

    result = [v for v in range(MAX_XOR) if dp[v] != INF]
    print(len(result))
    print(*result)

solve()

